mapper.select:
/* 인사평가만 서비스 하는지 여부 데이터 return login.selectIsOnlyInsa */
SELECT CASE WHEN LOCATE('03', A.SERVICE_TYPE) = 0 AND LOCATE('04', A.SERVICE_TYPE) > 0 THEN 'Y'
            ELSE 'N' END AS IS_ONLY_INSA_YN
  FROM COM_COMPINFO_DETAIL A
 WHERE A.COMP_ID = #{compId}
   AND A.CURRENT_SEQ = 'Y'

/* 로그인 사용자의 연도별 성과조직 목록 조회 login.selectUserScDeptList */
SELECT M.YEAR, M.SC_DEPT_ID
FROM V_ROLE_USER U
JOIN ORG_INSA_DEPT_MAPPING M
ON U.COMP_ID = M.COMP_ID
AND U.DEPT_ID = M.DEPT_ID
WHERE U.COMP_ID = #{compId}
AND U.USER_ID = #{userId}
ORDER BY M.YEAR

/* 서비스 사용여부 조회 login.selectServiceUseYn */
SELECT

    'Y' USE_YN
FROM COM_COMPINFO
WHERE COMP_ID = #{compId}

mapper.update:
/* 인증시도 횟수 조회 login.updateAccessCertificationStatusData */
UPDATE COM_ACCESS_AUTH
SET LAST_OCCUR_DATETIME = NOW(),
STATUS = #{status},
FAIL_COUNT = #{failCount}
WHERE COMP_ID = #{compId}
AND USER_ID = #{userId}
AND IN_TYPE = #{inType}

mapper.delete:
/* 인증시도 횟수 조회 login.deleteAccessCertificationStatusData */
DELETE FROM COM_ACCESS_AUTH
WHERE COMP_ID = #{compId}
AND USER_ID = #{userId}
AND IN_TYPE = #{inType}

mapper.update:
/*	OTP인증일시 업데이트	login.updateOTPReqDt	*/
UPDATE COM_OTP_AUTH
SET REQ_DT=now()
WHERE COMP_ID=#{compId}
AND USER_ID=#{userId}

mapper.select:
/*	사용 가능한 토큰여부 	login.selectAvailableTokenYn	*/
SELECT CASE WHEN COUNT(1)= 0 THEN 'Y' ELSE 'N' END
FROM COM_ACCESS_CERTIFICATION_LOG
WHERE IN_TYPE = 'jwt'
AND COMP_ID = #{compId}
AND USER_ID = #{userId}
AND TOKEN = #{token}

/* 고객사별 메뉴 갯수 조회  */
SELECT COUNT(*)
FROM COM_PGM

/* 전체 관리자 확인 여부  login.selectAuth */
SELECT AUTH_GUBUN
FROM COM_ADMIN
WHERE USER_ID = #{userId}
AND AUTH_GUBUN = '01'

/* 전체 관리자 확인 여부  login.selectIpList */
SELECT ALLOW_IP
FROM COM_ACCESS_ACL
WHERE USER_ID = #{userId}

/* 전체 관리자 확인 여부 login.beforePwdList */
SELECT PASSWD
FROM COM_USERINFO_PW_CHANGE
WHERE USER_ID = #{userId}
ORDER BY SEQ DESC
LIMIT ${limit}

/* 전체 관리자 확인 여부 login.pwCnt */
SELECT PW_CNT
FROM COM_COMPINFO
WHERE COMP_ID = #{compId}
